const body = $input.first().json || {};
const data = $input.first().json.body.sunAzimuthRanges

if (!Array.isArray(data)) {
  return [{ json: { statusCode: 400, error: "Expected 'sunAzimuthRanges' to be an array" } }];
}

const filtered = data.filter(e => e.id !== null && e.id !== undefined);

if (filtered.length === 0) {
  return [{ json: { statusCode: 200, message: "No valid entries with ID > 0 to insert/update." } }];
}

const values = [];
const params = [];

filtered.forEach((entry, i) => {
  const base = i * 13;
  values.push(
    `($${base+1}, $${base+2}, $${base+3}, $${base+4}, $${base+5}, $${base+6}, $${base+7}, $${base+8}, $${base+9}, $${base+10}, $${base+11}, $${base+12}, $${base+13})`
  );

  params.push(
    entry.id,
    entry.minPulses,
    entry.maxPulses,
    entry.minIntensity,
    entry.maxIntensity,
    entry.minDuration,
    entry.maxDuration,
    entry.minInterval,
    entry.maxInterval,
    entry.minAzimuth,
    entry.maxAzimuth,
    "SunAzimuth",
    entry.active === false ? false : true
  );
});

